class Solution {
public:
    int findSpecialInteger(vector<int>& arr) {
        unordered_map<int, int> count;
        for (int num : arr) {
            count[num]++;
        }
        for (auto& pair : count) {
            if (pair.second > arr.size() / 4) {
                return pair.first;
            }
        }
        return -1;
    }
};
